mapper.select:
select * from sub_centrality

     and `id` = #{id}
     and `centrality_id` = #{centralityId}
     and `customer_id` = #{customerId}
     and `user_id` = #{userId}
     and `iam_id` = #{iamId}
     and `repair_time` = #{repairTime}
     and `iam_content` like concat('%', #{iamContent}, '%')

order by id desc
